import { Component, EventEmitter, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { CustomerService } from '../../core/services/customer.service';
import { CustomerRequest } from '../../core/models/customer.model';

@Component({
  selector: 'app-customer-form',
  templateUrl: './customer-form.component.html',
  styleUrls: ['./customer-form.component.scss']
})
export class CustomerFormComponent implements OnInit {

  @Output() customerCreated = new EventEmitter<void>();

  customerForm!: FormGroup;
  isLoading    = false;
  errorMessage = '';
  successMessage = '';

  // yyyy-MM-dd in local time — avoids UTC offset shifting the date to yesterday
  readonly maxDate = new Date().toLocaleDateString('en-CA');

  constructor(
    private readonly fb: FormBuilder,
    private readonly customerService: CustomerService
  ) {}

  ngOnInit(): void {
    this.initForm();
  }

  get firstName()   { return this.customerForm.get('firstName')!;   }
  get lastName()    { return this.customerForm.get('lastName')!;     }
  get dateOfBirth() { return this.customerForm.get('dateOfBirth')!;  }

  onSubmit(): void {
    if (this.customerForm.invalid) {
      this.customerForm.markAllAsTouched();
      return;
    }

    this.isLoading     = true;
    this.errorMessage  = '';
    this.successMessage = '';

    const request: CustomerRequest = this.customerForm.value;

    this.customerService.createCustomer(request).subscribe({
      next: () => {
        this.isLoading      = false;
        this.successMessage = 'Customer created successfully!';
        this.customerForm.reset();
        this.customerCreated.emit();
      },
      error: (err: Error) => {
        this.isLoading    = false;
        this.errorMessage = err.message;
      }
    });
  }

  onReset(): void {
    this.customerForm.reset();
    this.errorMessage   = '';
    this.successMessage = '';
  }

  private initForm(): void {
    this.customerForm = this.fb.group({
      firstName:   ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
      lastName:    ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
      dateOfBirth: ['', [Validators.required]]
    });
  }
}
<div class="form-card">
  <h2 class="form-title">Add New Customer</h2>

  <div *ngIf="successMessage" class="alert alert-success">
    {{ successMessage }}
  </div>

  <div *ngIf="errorMessage" class="alert alert-error">
    {{ errorMessage }}
  </div>

  <form [formGroup]="customerForm" (ngSubmit)="onSubmit()" novalidate>

    <!-- First Name -->
    <div class="form-group">
      <label for="firstName">First Name <span class="required">*</span></label>
      <input
        id="firstName"
        type="text"
        formControlName="firstName"
        placeholder="Enter first name"
        [class.input-error]="firstName.invalid && firstName.touched"
      />
      <div class="error-message" *ngIf="firstName.invalid && firstName.touched">
        <span *ngIf="firstName.errors?.['required']">First name is required.</span>
        <span *ngIf="firstName.errors?.['minlength']">Minimum 2 characters required.</span>
      </div>
    </div>

    <!-- Last Name -->
    <div class="form-group">
      <label for="lastName">Last Name <span class="required">*</span></label>
      <input
        id="lastName"
        type="text"
        formControlName="lastName"
        placeholder="Enter last name"
        [class.input-error]="lastName.invalid && lastName.touched"
      />
      <div class="error-message" *ngIf="lastName.invalid && lastName.touched">
        <span *ngIf="lastName.errors?.['required']">Last name is required.</span>
        <span *ngIf="lastName.errors?.['minlength']">Minimum 2 characters required.</span>
      </div>
    </div>

    <!-- Date of Birth -->
    <div class="form-group">
      <label for="dateOfBirth">Date of Birth <span class="required">*</span></label>
      <input
        id="dateOfBirth"
        type="date"
        formControlName="dateOfBirth"
        [max]="maxDate"
        [class.input-error]="dateOfBirth.invalid && dateOfBirth.touched"
      />
      <div class="error-message" *ngIf="dateOfBirth.invalid && dateOfBirth.touched">
        <span *ngIf="dateOfBirth.errors?.['required']">Date of birth is required.</span>
      </div>
    </div>

    <!-- Actions -->
    <div class="form-actions">
      <button type="button" class="btn btn-secondary" (click)="onReset()">Reset</button>
      <button type="submit" class="btn btn-primary" [disabled]="isLoading">
        <span *ngIf="isLoading">Saving...</span>
        <span *ngIf="!isLoading">Save Customer</span>
      </button>
    </div>

  </form>
</div>
